 57	#define FAIL(...)					\
 58		do {						\
 59			bst_result = Failed;			\
 60			bs_trace_error_time_line(__VA_ARGS__);	\
 61		} while (0)
 62	
 63	#define PASS(...)					\
 64		do {						\
 65			bst_result = Passed;			\
 66			bs_trace_info_time(1, __VA_ARGS__);	\
 67		} while (0)
