115	static void connected(struct bt_conn *conn, uint8_t conn_err)
116	{
117		int err;
118	
119		printk("Connected.\n");
120	
121		is_connected = true;
122	
123		err = bt_conn_disconnect(conn, BT_HCI_ERR_REMOTE_USER_TERM_CONN);
124		if (err) {
125			printk("Disconnection failed (err %d).\n", err);
126		}
127	}
128	
129	static void disconnected(struct bt_conn *conn, uint8_t reason)
130	{
131		printk("Disconnected.\n");
132	
133		is_disconnected = true;
134	}
