170	static void test_advx_main(void)
171	{
172		struct bt_le_ext_adv_start_param ext_adv_param;
173		struct bt_le_ext_adv *adv;
174		uint8_t num_sent_expected;
175		struct bt_data sd[1];
176		uint16_t evt_prop;
177		uint8_t adv_type;
178		uint16_t handle;
179		uint8_t phy_p;
180		uint8_t phy_s;
181		int err;
182	
183		printk("\n*Extended Advertising test*\n");
184	
185		printk("Bluetooth initializing...");
186		err = bt_enable(NULL);
187		if (err) {
188			goto exit;
189		}
190		printk("success.\n");
191	
192		printk("Connectable advertising...");
193		err = bt_le_adv_start(BT_LE_ADV_CONN_FAST_2, ad, ARRAY_SIZE(ad), NULL, 0);
194		if (err) {
195			printk("Advertising failed to start (err %d)\n", err);
196			return;
197		}
198		printk("success.\n");
199	
200		printk("Waiting for connection...");

printk("Waiting for connection...");
while (!is_connected) {
	k_sleep(K_MSEC(100));
}
printk("success.\n");

printk("Waiting for disconnect...");
while (!is_disconnected) {
	k_sleep(K_MSEC(100));
}
printk("success.\n");

printk("Stop advertising...");
err = bt_le_adv_stop();
if (err) {
	goto exit;
}
printk("success.\n");

printk("AD Data set...");
handle = 0U;
err = ll_adv_data_set(handle, sizeof(adv_data), adv_data);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Directed advertising, parameter set...");
err = ll_adv_params_set(handle, 0, 0, BT_HCI_ADV_DIRECT_IND,
			OWN_ADDR_TYPE, PEER_ADDR_TYPE, PEER_ADDR,
			ADV_CHAN_MAP, FILTER_POLICY,
			0, 0, 0, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Connectable advertising, parameter set...");
err = ll_adv_params_set(handle, 0, ADV_INTERVAL, BT_HCI_ADV_NONCONN_IND,
			OWN_ADDR_TYPE, PEER_ADDR_TYPE, PEER_ADDR,
			ADV_CHAN_MAP, FILTER_POLICY,
			0, 0, 0, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Enabling...");
err = ll_adv_enable(handle, 1, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(100));

printk("Disabling...");
err = ll_adv_enable(handle, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Directed advertising, parameter set...");
err = ll_adv_params_set(handle, 0, 0, BT_HCI_ADV_DIRECT_IND,
			OWN_ADDR_TYPE, PEER_ADDR_TYPE, PEER_ADDR,
			ADV_CHAN_MAP, FILTER_POLICY,
			0, 0, 0, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

printk("AD Data set...");
handle = 0U;
err = ll_adv_data_set(handle, sizeof(adv_data1), adv_data1);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Connectable advertising, parameter set...");
err = ll_adv_params_set(handle, 0, ADV_INTERVAL, BT_HCI_ADV_NONCONN_IND,
			OWN_ADDR_TYPE, PEER_ADDR_TYPE, PEER_ADDR,
			ADV_CHAN_MAP, FILTER_POLICY,
			0, 0, 0, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Enabling...");
err = ll_adv_enable(handle, 1, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(100));

printk("Disabling...");

printk("Disabling...");
err = ll_adv_enable(handle, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Create scannable extended advertising set...");
err = bt_le_ext_adv_create(BT_LE_EXT_ADV_SCAN, &adv_callbacks,
			   &adv);
if (err) {
	goto exit;
}
printk("success.\n");

/* Scannable advertiser need to have scan response data */
printk("Set scan response data...");
sd[0].type = BT_DATA_NAME_COMPLETE;
sd[0].data_len = sizeof(CONFIG_BT_DEVICE_NAME) - 1;
sd[0].data = CONFIG_BT_DEVICE_NAME;
err = bt_le_ext_adv_set_data(adv, NULL, 0, sd, 1);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Start scannable advertising...");
ext_adv_param.timeout = 0;
ext_adv_param.num_events = 0;
err = bt_le_ext_adv_start(adv, &ext_adv_param);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(500));

printk("Stopping scannable advertising...");
err = bt_le_ext_adv_stop(adv);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Removing scannable adv set...");
err = bt_le_ext_adv_delete(adv);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Create connectable extended advertising set...");
is_connected = false;
is_disconnected = false;
err = bt_le_ext_adv_create(BT_LE_EXT_ADV_CONN, &adv_callbacks, &adv);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Start advertising...");
ext_adv_param.timeout = 0;
ext_adv_param.num_events = 0;
err = bt_le_ext_adv_start(adv, &ext_adv_param);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Waiting for connection...");
while (!is_connected) {
	k_sleep(K_MSEC(100));
}
printk("success.\n");

printk("Waiting for disconnect...");
while (!is_disconnected) {
	k_sleep(K_MSEC(100));
}
printk("success.\n");

printk("Removing connectable adv aux set...");
err = bt_le_ext_adv_delete(adv);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(1000));

printk("Starting non-connectable advertising...");
err = bt_le_adv_start(BT_LE_ADV_NCONN, ad, ARRAY_SIZE(ad), NULL, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Stopping advertising...");
err = bt_le_adv_stop();

err = bt_le_adv_stop();
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(1000));

printk("Create connectable advertising set...");
err = bt_le_ext_adv_create(BT_LE_ADV_CONN_FAST_2, &adv_callbacks, &adv);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Start advertising using extended commands (max_events)...");
is_sent = false;
num_sent_actual = 0;
num_sent_expected = 3;
ext_adv_param.timeout = 0;
ext_adv_param.num_events = 3;
err = bt_le_ext_adv_start(adv, &ext_adv_param);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Waiting...");
while (!is_sent) {
	k_sleep(K_MSEC(100));
}
printk("done.\n");

if (num_sent_actual != num_sent_expected) {
	FAIL("Num sent actual = %u, expected = %u\n", num_sent_actual,
	     num_sent_expected);
}

k_sleep(K_MSEC(1000));

printk("Start advertising using extended commands (duration)...");
is_sent = false;
num_sent_actual = 0;
num_sent_expected = 5;
ext_adv_param.timeout = 50;
ext_adv_param.num_events = 0;
err = bt_le_ext_adv_start(adv, &ext_adv_param);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Waiting...");
while (!is_sent) {
	k_sleep(K_MSEC(100));
}
printk("done.\n");

if (num_sent_actual != num_sent_expected) {
	FAIL("Num sent actual = %u, expected = %u\n", num_sent_actual,
	     num_sent_expected);
}

k_sleep(K_MSEC(1000));

printk("Re-enable advertising using extended commands (max_events)...");
is_sent = false;
num_sent_actual = 0;
num_sent_expected = 3;
ext_adv_param.timeout = 0;
ext_adv_param.num_events = 3;
err = bt_le_ext_adv_start(adv, &ext_adv_param);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(100));

printk("Setting advertising random address before re-enabling...");
handle = 0x0000;
err = ll_adv_aux_random_addr_set(handle, own_addr_reenable);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Re-enabling...");
handle = 0x0000;
err = ll_adv_enable(handle, 1,
		    ext_adv_param.timeout,
		    ext_adv_param.num_events);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Waiting...");
while (!is_sent) {
	k_sleep(K_MSEC(100));
}

}
printk("done.\n");

if (num_sent_actual != num_sent_expected) {
	FAIL("Num sent actual = %u, expected = %u\n", num_sent_actual,
	     num_sent_expected);
}

k_sleep(K_MSEC(1000));

printk("Re-enable advertising using extended commands (duration)...");
is_sent = false;
num_sent_actual = 0;
num_sent_expected = 5;      /* 5 advertising events with a spacing of (100 ms +
			     * random_delay of upto 10 ms) transmit in
			     * the range of 400 to 440 ms
			     */
ext_adv_param.timeout = 50; /* Check there is atmost 5 advertising
			     * events in a timeout of 500 ms
			     */
ext_adv_param.num_events = 0;
err = bt_le_ext_adv_start(adv, &ext_adv_param);
if (err) {
	goto exit;
}
printk("success.\n");

/* Delay 100 ms, and the test should verify that re-enabling still
 * results in correct num of events.
 */
k_sleep(K_MSEC(100));

printk("Re-enabling...");
handle = 0x0000;
err = ll_adv_enable(handle, 1,
		    ext_adv_param.timeout,
		    ext_adv_param.num_events);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Waiting...");
while (!is_sent) {
	k_sleep(K_MSEC(100));
}
printk("done.\n");

if (num_sent_actual != num_sent_expected) {
	FAIL("Num sent actual = %u, expected = %u\n", num_sent_actual,
	     num_sent_expected);
}

k_sleep(K_MSEC(1000));

printk("Start advertising using extended commands (disable)...");
ext_adv_param.timeout = 0;
ext_adv_param.num_events = 5;
err = bt_le_ext_adv_start(adv, &ext_adv_param);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Stopping advertising using extended commands...");
err = bt_le_ext_adv_stop(adv);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(1000));

printk("Setting advertising random address...");
handle = 0x0000;
err = ll_adv_aux_random_addr_set(handle, own_addr);
if (err) {
	goto exit;
}
printk("success.\n");

printk("Starting non-conn non-scan without aux 1M advertising...");
evt_prop = EVT_PROP_TXP;
adv_type = 0x07; /* Adv. Ext. */
phy_p = ADV_PHY_1M;
phy_s = ADV_PHY_2M;
err = ll_adv_params_set(handle, evt_prop, ADV_INTERVAL, adv_type,
			OWN_ADDR_TYPE, PEER_ADDR_TYPE, PEER_ADDR,
			ADV_CHAN_MAP, FILTER_POLICY, ADV_TX_PWR,
			phy_p, ADV_SEC_SKIP, phy_s, ADV_SID,
			SCAN_REQ_NOT);
if (err) {
	goto exit;
}

printk("enabling...");
err = ll_adv_enable(handle, 1, 0, 0);
if (err) {
	goto exit;

	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Disabling...");
err = ll_adv_enable(handle, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(1000));

printk("Enabling non-conn non-scan without aux 1M advertising...");
err = ll_adv_enable(handle, 1, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Adding data, so non-conn non-scan with aux 1M advertising...");
err = ll_adv_aux_ad_data_set(handle, AD_OP, AD_FRAG_PREF,
			     sizeof(adv_data), (void *)adv_data);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Update advertising data 1...");
err = ll_adv_aux_ad_data_set(handle, AD_OP, AD_FRAG_PREF,
			     sizeof(adv_data1), (void *)adv_data1);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Update advertising data 2...");
err = ll_adv_aux_ad_data_set(handle, AD_OP, AD_FRAG_PREF,
			     sizeof(adv_data2), (void *)adv_data2);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Starting directed advertising...");
const bt_addr_le_t direct_addr = {
	.type = BT_ADDR_LE_RANDOM,
	.a = {
		.val = {0x11, 0x22, 0x33, 0x44, 0x55, 0xC6}
	}
};
const struct bt_le_adv_param adv_param = {
	.options = BT_LE_ADV_OPT_CONN,
	.peer = &direct_addr,
};
err = bt_le_adv_start(&adv_param, NULL, 0, NULL, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(2000));

printk("Disabling...");
err = ll_adv_enable(handle, 0, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(1000));

if (IS_ENABLED(CONFIG_BT_CTLR_PRIVACY)) {
	printk("Add to resolving list...");
	bt_addr_le_t peer_id_addr = {
		.type = BT_ADDR_LE_RANDOM,
		.a = {
			.val = {0xc6, 0xc7, 0xc8, 0xc9, 0xc1, 0xcb}
		}
	};
	uint8_t pirk[16] = {0xAB, 0xBA, 0xAB, 0xBA, 0xAB, 0xBA, 0xAB, 0xBA,
			    0xAB, 0xBA, 0xAB, 0xBA, 0xAB, 0xBA, 0xAB, 0xBA};
	uint8_t lirk[16] = {0x12, 0x21, 0x12, 0x21, 0x12, 0x21, 0x12, 0x21,
			    0x12, 0x21, 0x12, 0x21, 0x12, 0x21, 0x12, 0x21};

	err = ll_rl_add(&peer_id_addr, pirk, lirk);
	if (err) {
		goto exit;
	}
	printk("success.\n");

	printk("Enable resolving list...");
	err = ll_rl_enable(BT_HCI_ADDR_RES_ENABLE);
	if (err) {
		goto exit;
	}
	printk("success.\n");
}

printk("Enabling extended...");
err = ll_adv_enable(handle, 1, 0, 0);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Starting periodic 1M advertising...");
err = ll_adv_sync_param_set(handle, ADV_INTERVAL_PERIODIC, 0);
if (err) {
	goto exit;
}

printk("enabling periodic...");
err = ll_adv_sync_enable(handle, BT_HCI_LE_SET_PER_ADV_ENABLE_ENABLE);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Update advertising data 1...");
err = ll_adv_aux_ad_data_set(handle, AD_OP, AD_FRAG_PREF,
			     sizeof(adv_data1), (void *)adv_data1);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Update advertising data 2...");
err = ll_adv_aux_ad_data_set(handle, AD_OP, AD_FRAG_PREF,
			     sizeof(adv_data2), (void *)adv_data2);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Update periodic advertising data 1...");
err = ll_adv_sync_ad_data_set(handle, AD_OP, sizeof(per_adv_data1),
			      (void *)per_adv_data1);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Update periodic advertising data 2...");
err = ll_adv_sync_ad_data_set(handle, AD_OP, sizeof(per_adv_data2),
			      (void *)per_adv_data2);
if (err) {
	goto exit;
}
printk("success.\n");

k_sleep(K_MSEC(400));

printk("Update periodic advertising data 3...");
err = ll_adv_sync_ad_data_set(handle, AD_OP, sizeof(per_adv_data3),
			      (void *)per_adv_data3);
if (err) {
	goto exit;
